onTextChanged:
{{(() => {
     // Clear existing timeout
     clearInterval(appsmith.store.newDropoffGeoTimeout);

     if (NewDropoffAddressInput.text && NewDropoffAddressInput.text.length > 2) {
       // Create new timeout
       const timeoutId = setInterval(() => {
         GeocodeNewDropoffAddress.run().then(() => {
           if (GeocodeNewDropoffAddress.data?.length > 0) {
             LocationManager.updateNewDropoffFromGeocode();
           }
         });
         // Clear after running once
         clearInterval(appsmith.store.newDropoffGeoTimeout);
       }, 1500);

       // Store timeout ID
       storeValue('newDropoffGeoTimeout', timeoutId);
     }
   })()}}
